// app/src/domain/adjudication/adjudicator.ts — the pure adjudication core.
// adjudicateLine(input) -> decision + accumulator deltas. No I/O: it reads a snapshot
// and returns the deltas for the caller to persist, which is what makes it deterministic
// and unit-testable with plain objects (no DB for the pure cycles).

import type { LineItem, LineItemStatus } from "../entities/line-item";
import type { Policy } from "../entities/policy";
import { formatUsd } from "../money/cents";
import { ReasonCode } from "../reason-codes";
import type { CoverageRule } from "../rules/coverage-rule";

export type AccumulatorSnapshot = {
  deductibleMetCents: number;
  oopMetCents: number;
  limitUsed: number; // cents for a dollar limit, a count for a visit limit
};

export type AdjudicateLineInput = {
  line: LineItem;
  policy: Policy;
  rule: CoverageRule | undefined; // matched by serviceCode; undefined => NO_COVERAGE
  serviceDate: string; // claim-level ISO date (policy-active check)
  acc: AccumulatorSnapshot; // read-only snapshot taken at claim start
  alreadyAdjudicated: boolean; // true => DUPLICATE_LINE_ITEM
};

export type AdjudicateLineResult = {
  status: LineItemStatus; // APPROVED | DENIED (NEEDS_REVIEW only via dispute)
  payableCents: number; // plan pays
  memberResponsibilityCents: number; // member owes
  reasons: ReasonCode[]; // dominant code first, then any breakdown
  explanation: string; // EOB sentence citing the rule + the numbers used
  deltas: { deductibleIncCents: number; oopIncCents: number; limitInc: number };
};

export function adjudicateLine(input: AdjudicateLineInput): AdjudicateLineResult {
  const { rule, line } = input;

  // Cycle 1 — the full-coverage happy path: plan pays 100%, member owes nothing,
  // deductible/OOP/limit untouched. Every other branch (gates, copay, coinsurance,
  // limits, OOP) arrives in a later cycle, each driven by its own failing test.
  if (rule && rule.covered && !rule.excluded && rule.costShare.type === "full_coverage") {
    return {
      status: "APPROVED",
      payableCents: line.billedCents,
      memberResponsibilityCents: 0,
      reasons: [ReasonCode.APPROVED],
      explanation: `Full coverage: the plan pays 100% (${formatUsd(line.billedCents)}); you owe ${formatUsd(0)}.`,
      deltas: { deductibleIncCents: 0, oopIncCents: 0, limitInc: 0 },
    };
  }

  throw new Error("adjudicateLine: only full_coverage is implemented (TDD cycle 1)");
}

// app/tests/builders.ts — AAA builders. Each returns a fully-valid, camelCase,
// integer-cents object; a test overrides only the field(s) it asserts on, so the
// load-bearing fact of each test stands out and the rest recedes. No `any`.

import type { CoverageRule, LineItem, Policy } from "../src/domain/types";
import type {
  AccumulatorSnapshot,
  AdjudicateLineInput,
} from "../src/domain/adjudication/adjudicator";

export const aPolicy = (overrides: Partial<Policy> = {}): Policy => ({
  id: "pol_test_1",
  memberId: "mem_test_1",
  planYear: 2026,
  effectiveDate: "2026-01-01",
  terminationDate: "2026-12-31",
  deductibleCents: 50_000, // $500.00
  oopMaxCents: 300_000, // $3,000.00
  ...overrides,
});

export const aCoverageRule = (overrides: Partial<CoverageRule> = {}): CoverageRule => ({
  policyId: "pol_test_1",
  serviceCode: "PREVENTIVE",
  covered: true,
  excluded: false,
  costShare: { type: "full_coverage" },
  appliesDeductible: false,
  limit: { unit: "none" },
  requiresPriorAuth: false,
  ...overrides,
});

export const aLineItem = (overrides: Partial<LineItem> = {}): LineItem => ({
  id: "li_test_1",
  claimId: "clm_test_1",
  serviceCode: "PREVENTIVE",
  billedCents: 12_000, // $120.00 — integer cents, never a float
  units: 1,
  priorAuthPresent: true,
  status: "PENDING",
  fingerprint: "mem_test_1|PREVENTIVE|2026-06-19|12000",
  ...overrides,
});

export const anAccumulator = (
  overrides: Partial<AccumulatorSnapshot> = {},
): AccumulatorSnapshot => ({
  deductibleMetCents: 0,
  oopMetCents: 0,
  limitUsed: 0,
  ...overrides,
});

export const anAdjudicateInput = (
  overrides: Partial<AdjudicateLineInput> = {},
): AdjudicateLineInput => ({
  line: aLineItem(),
  policy: aPolicy(),
  rule: aCoverageRule(),
  serviceDate: "2026-06-19", // within the default policy window
  acc: anAccumulator(),
  alreadyAdjudicated: false,
  ...overrides,
});

// app/src/domain/reason-codes.ts — canonical ReasonCode vocabulary.
// Modeled as a const-object + union (NOT a runtime `enum`) so it survives the
// erasableSyntaxOnly tsconfig flag while keeping the same string values.
// One dominant code classifies each decision; the explanation carries the breakdown.

export const ReasonCode = {
  APPROVED: "APPROVED",
  NO_COVERAGE: "NO_COVERAGE",
  EXCLUDED: "EXCLUDED",
  LIMIT_EXCEEDED: "LIMIT_EXCEEDED",
  DEDUCTIBLE_APPLIED: "DEDUCTIBLE_APPLIED",
  COPAY_APPLIED: "COPAY_APPLIED",
  COINSURANCE_APPLIED: "COINSURANCE_APPLIED",
  OOP_MAX_REACHED: "OOP_MAX_REACHED",
  PRIOR_AUTH_REQUIRED: "PRIOR_AUTH_REQUIRED",
  DUPLICATE_LINE_ITEM: "DUPLICATE_LINE_ITEM",
  POLICY_NOT_ACTIVE: "POLICY_NOT_ACTIVE",
  DISPUTED_OVERRIDE: "DISPUTED_OVERRIDE", // reserved for a v2 reviewer override; unused in v1
} as const;

export type ReasonCode = (typeof ReasonCode)[keyof typeof ReasonCode];

